import React, { useState, useRef, Fragment } from 'react';
import { Breadcrumb, Button, Drawer, Tooltip, Typography } from 'antd';
import { PageContainer } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { fileTransferAudits } from '@/services/api';
import type { API } from '@/services/typings';
import { csvFormat, getTablePaginationConfig, SaveCsv, t } from '../../../global';
import { ArrowLeftOutlined, ArrowRightOutlined, InfoCircleOutlined } from '@ant-design/icons';
import { useIntl } from '@umijs/max';

function formatBytes(a: number, b = 2) {
  if (!+a) return '0 Bytes';
  const c = 0 > b ? 0 : b,
    d = Math.floor(Math.log(a) / Math.log(1024));
  return `${parseFloat((a / Math.pow(1024, d)).toFixed(c))} ${['Bytes', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB'][d]
    }`;
}

interface IInfo {
  name?: string;
  ip?: string;
  num?: number;
  files?: [string, number][];
}

const { Text } = Typography;

// not good enough
const EllipsisMiddle: React.FC<{ suffixCount: number; children: string }> = ({
  suffixCount,
  children,
}) => {
  let start = children;
  let suffix = '';
  if (children.length > suffixCount) {
    start = children.slice(0, children.length - suffixCount).trim();
    suffix = children.slice(-suffixCount).trim();
  }
  return (
    <Tooltip title={children}>
      <Text style={{ maxWidth: '100%' }} ellipsis={{ suffix }}>
        {start}
      </Text>
    </Tooltip>
  );
};

const AuditList: React.FC = () => {
  const actionRef = useRef<ActionType>();
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [info, setInfo] = useState<IInfo>();
  const [pageParams, setPageParams] = useState<Partial<API.PageParams>>();
  const intl = useIntl();

  const onShowDrawer = (i: IInfo) => {
    setInfo(i);
    setDrawerOpen(true);
  };

  const plain = (text: string, defaultMessage = '') => t(text, true, defaultMessage || text, intl) as string;

  const directionEnumMap = (i: number) => {
    switch (i) {
      case 0:
        return `${plain('Remote')}->${plain('Local')}`;
      case 1:
        return `${plain('Local')}->${plain('Remote')}`;
      default:
        return i.toString();
    }
  };

  const exportCsv = async () => {
    let allItems: API.FileAuditListItem[] = [];
    let total = 0;
    const pageSize = 100;
    let current = 0;
    do {
      current++;
      const items = await fileTransferAudits({
        ...pageParams,
        current: current,
        pageSize: pageSize,
      });
      if (total == 0 && items.total != null) {
        total = items.total;
      }
      if (items.data != null) {
        allItems = allItems.concat(items.data);
      }
    } while (current < 10 && pageSize * current < total);

    const titles = ['Remote', 'Local', 'Time', 'Direction', 'File', 'Detail'];
    titles.forEach((s, index) => (titles[index] = plain(s)));
    const rows: string[][] = [];
    allItems.forEach((record) => {
      const row: string[] = [];
      row.push(record.remote);
      row.push(record.local ?? '');
      row.push(csvFormat(new Date((record.created_at || 0) * 1000).toLocaleString()));
      row.push(directionEnumMap(record.type || 0));
      row.push(record.path || '');
      let detail;
      try {
        const local_info: IInfo = JSON.parse(record.info || '{}');
        delete local_info.ip;
        delete local_info.name;
        detail = JSON.stringify(local_info);
      } catch (e) { }
      row.push(csvFormat(detail ?? ''));
      rows.push(row);
    });
    SaveCsv(
      titles,
      rows,
      plain('pages.AuditList.FileAuditList.exportFilename', 'FileTranferAudit'),
    );
  };

  const columns: ProColumns<API.FileAuditListItem>[] = [
    {
      title: t('ID'),
      dataIndex: 'remote',
      hideInDescriptions: true,
      hideInTable: true,
      tip: t('Remote device', true) as string,
    },
    {
      title: t('Name'),
      dataIndex: 'remote_device_name',
      hideInDescriptions: true,
      hideInTable: true,
      tip: t('Remote device', true) as string,
    },
    {
      title: t('Remote'),
      dataIndex: 'remote',
      tip: t('remoteTip', true, 'Remotely controlled computer or terminal') as string,
      hideInSearch: true,
    },
    {
      title: t('Local'),
      dataIndex: 'local',
      search: false,
      width: 200,
      render: (_, record) => {
        let txt = record.local || '';
        let local_info = {} as any;
        try {
          local_info = JSON.parse(record.info || '{}');
          if (!txt) txt = '';
          let name = local_info['name'] || '';
          if (txt.indexOf(name) == -1) txt += ' ' + name;
          let ip = (local_info['ip'] || '').replace("::ffff:", "");
          if (ip) txt += '@' + ip;
        } catch (e) { }
        return txt;
      },
    },
    {
      title: t('Time'),
      dataIndex: 'created_at',
      valueType: 'dateTime',
      render: (_, record) => new Date((record.created_at || 0) * 1000).toLocaleString(),
    },
    {
      title: t('Direction'),
      dataIndex: 'type',
      valueType: 'select',
      render: (_, record) => {
        const tip = directionEnumMap(record.type || 0);
        return <Tooltip title={tip}>
          {record.type == 1 ? <ArrowLeftOutlined /> : <ArrowRightOutlined />}
        </Tooltip>;
      },
      valueEnum: {
        0: {
          text: directionEnumMap(0),
        },
        1: {
          text: directionEnumMap(1),
        },
      }
    },
    {
      title: t('File'),
      search: false,
      dataIndex: 'path',
      width: '30%',
      ellipsis: true,
      tip: t('pages.AuditList.FileAuditList.pathTip', true, 'Path of Remote Device') as string,
      render: (_, record) => <EllipsisMiddle suffixCount={16}>{record.path || ''}</EllipsisMiddle>,
    },
    {
      title: t('Detail'),
      dataIndex: 'info',
      search: false,
      align: 'center',
      render: (_, record) => {
        try {
          const local_info: IInfo = JSON.parse(record.info || '{}');
          if (record.is_file) {
            if (local_info.num == 1 && local_info.files && local_info.files.length == 1) {
              return formatBytes(local_info.files[0][1]);
            }
          } else {
            if (local_info.num != undefined && local_info.files) {
              const text = `${local_info.num} ${t(
                'pages.AuditList.FileAuditList.files',
                true,
                'Files',
              )}`;
              if (local_info.num > 0 && local_info.files.length > 0) {
                return (
                  <Button type="link" onClick={() => onShowDrawer(local_info)}>
                    {' '}
                    {text}
                  </Button>
                );
              } else {
                return text;
              }
            }
          }
        } catch (e) { }
        return '';
      },
    },
  ];

  return (
    (<PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.audit-list', true) },
          { title: t('menu.list.audit-list.File', true) },
        ]} />
      )}
    >
      <ProTable<API.FileAuditListItem, API.PageParams>
        headerTitle={t('Log List')}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'filelist_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        request={fileTransferAudits}
        columns={columns}
        beforeSearchSubmit={(params) => {
          setPageParams(params);
          return params;
        }}
        toolBarRender={() => [
          <Tooltip title={t('exportCsvTip', true, 'Export up to 1000 records at a time')}>
            <Button type="default" onClick={exportCsv}>
              {t('Export as csv')}
            </Button>
          </Tooltip>,
        ]}
        pagination={getTablePaginationConfig("file_audit_list")}
      />
      <Drawer
        title={
          <Fragment>
            {t('Detail', true)}
            {info?.num && info?.files?.length && info?.num > info.files.length ? (
              <Tooltip
                title={t(
                  'pages.AuditList.FileAuditList.limitedTip',
                  true,
                  'Show the 10 largest files by size',
                )}
              >
                <InfoCircleOutlined style={{ float: 'right' }} />
              </Tooltip>
            ) : (
              ''
            )}
          </Fragment>
        }
        placement="right"
        onClose={() => setDrawerOpen(false)}
        open={drawerOpen}
      >
        {info?.files?.map(([name, size]) => (
          <p>
            <span>{name}</span>
            <span style={{ float: 'right' }}>{formatBytes(size)}</span>
          </p>
        ))}
        {info?.num && info?.files?.length && info?.num > info.files.length ? '...' : ''}
      </Drawer>
    </PageContainer>)
  );
};

export default AuditList;
